module.render:
const columns = parseInt(args.columns, 10) || 3;
const gap = args.gap || '1rem';
let html = `\n\n<div class="mdp-mod-grid" style="grid-template-columns: repeat(${columns}, minmax(0, 1fr)); gap: ${gap};">\n`;
sections.forEach((section) => {
  const contentStr = section.trim();
  if (!contentStr) return;
  html += `<div class="mdp-mod-grid-card">\n\n${contentStr}\n\n</div>`;
});
html += `</div>\n\n`;
return html;
